import { PageContainer } from '@ant-design/pro-layout';
import { Link, useIntl, useParams } from '@umijs/max';
import TagsCard from '../DetailComponents/TagsCard'
import DeviceTable from '../DetailComponents/DeviceTable';
import { useEffect, useRef, useState } from 'react';
import { getSharedAbProfileByGuid, getAbTags } from '@/services/api';
import { API } from '@/services/typings';
import { Breadcrumb, Col, Row, message } from 'antd';
import { t } from '@/global';
import { ActionType } from '@ant-design/pro-table';


const AddressBookDetails: React.FC = (props) => {
  // https://umijs.org/blog/develop-blog-using-umi#api-%E8%B7%AF%E7%94%B1%E8%AE%BE%E8%AE%A1
  // https://github.com/umijs/umi-blog-example/blob/main/src/pages/posts/post.tsx
  // https://umijs.org/docs/api/api#useparams
  const params = useParams();
  const ab_guid = params.ab_guid as string;
  const [profile, setProfile] = useState<API.SharedAbProfile>();
  const [abTags, setAbTags] = useState<API.AbTag[]>([]);
  const deviceTableActionRef = useRef<ActionType>();
  const [selectedTags, setSelectedTags] = useState<string[]>([]);
  const [intersection, setIntersection] = useState(false);
  const intl = useIntl();

  const plain = (text: string, defaultMessage = '') => t(`pages.AddressBook.${text}`, true, defaultMessage || text, intl) as string;

  useEffect(() => {
    getSharedAbProfile();
    getTags();
  }, []);

  const getSharedAbProfile = async () => {
    try {
      const profile = await getSharedAbProfileByGuid(ab_guid, { hide_password: true });
      setProfile(profile);
    } catch (error) { }
  }

  const getTags = async () => {
    try {
      setAbTags(await getAbTags(ab_guid));
    } catch (error) {
      message.error(t(`Failed to get tags: ${error}`));
    }
  };

  return (
    < PageContainer
      header={{
        title: profile?.name,
        ghost: true,
      }}
      breadcrumbRender={(props, defaultDom) => <Breadcrumb items={[{
        title: <Link to="/ab">{plain('Shared')}</Link>
      },
      {
        title: profile?.name,
      },]} />}
    >
      <Row>
        <Col span={24}>
          {profile && <TagsCard personal={false} profile={profile} abTags={abTags} setAbTags={setAbTags} deviceTableActionRef={deviceTableActionRef}
            selectedTags={selectedTags} setSelectedTags={setSelectedTags} intersection={intersection} setIntersection={setIntersection} />}
        </Col>
      </Row>
      <Row style={{ marginTop: 20 }}>
        <Col span={24}>
          {profile && < DeviceTable personal={false} profile={profile} abTags={abTags} deviceTableActionRef={deviceTableActionRef}
            selectedTags={selectedTags} intersection={intersection} />}
        </Col>
      </Row>
    </PageContainer >
  )
};

export default AddressBookDetails;
